#include <bits/stdc++.h>
#define int long long
using namespace std;
const int maxn = 300050;
const int maxm = maxn << 1;
int N, M;
int a[maxn], t1, t2;
int Head[maxn], cnt;
int fa[maxn][31], dep[maxn];
struct Edge{
	int u, v, Next;
} edge[maxm];
void addedge (int u, int v) {
	edge[++cnt].u = u;
	edge[cnt].v = v;
	edge[cnt].Next = Head[u];
	Head[u] = cnt;
	return ;
}
void dfs (int u, int faa) {
	fa[u][0] = faa;
	dep[u] = dep[faa] + 1;
	for (int i = 1; i <= 30; i++) {
		fa[u][i] = fa[fa[u][i - 1]][i - 1];
	}
	for (int i = Head[u]; i; i = edge[i].Next) {
		int v = edge[i].v;
		if (v == faa) {
			continue;
		}
		dfs (v, u);
	}
}
int lca (int x, int y) {
	if (dep[x] < dep[y]) {
		swap (x, y);
	}
	for (int i = 30; i >= 0; i--) {
		if (dep[fa[x][i]] >= dep[y]) {
			x = fa[x][i];
		}
	}
	if (x == y) {
		return x;
	}
	for (int i = 30; i >= 0; i--){
		if (fa[x][i] != fa[y][i]){
			x = fa[x][i];
			y = fa[y][i];
		}
	}
	return fa[x][0];
}
int num[maxn];
void answer (int u, int faa) {
	for (int i = Head[u]; i; i = edge[i].Next) {
		int v = edge[i].v;
		if (v == faa) {
			continue;
		} 
		answer (v, u);
		num[u] += num[v];
	}
	return;
}
signed main() {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> N;
	for (int i = 1; i <= N; i++) {
		cin >> a[i];
	}
	for (int i = 1 ; i < N; i++) {
		cin >> t1 >> t2;
		addedge (t1, t2);
		addedge (t2, t1);
	}
	dfs (1, 0);
	for (int i = 1; i < N; i++) {
		int u = a[i], v = a[i + 1];
		int t = lca (u, v);
		num[fa[t][0]] -= 1;
		num[t] -= 1;
		num[u] += 1;
		num[v] += 1;
	}
	answer (1, 0);
	for (int i = 2; i <= N; i++) {
		num[a[i]]--;
	}
	for (int i = 1; i <= N; i++) {
		cout << num[i] << '\n';
	}
	return 0;
}
